import os
import glob
import re
import json
import pandas as pd

RAW_ORDERS_DIR = "/app/raw_orders"
RAW_SUPPLIER_DIR = "/app/raw_supplier_receipts"
RAW_WHOLESALER_DIR = "/app/raw_wholesaler_receipts"
RAW_STORE_DIR = "/app/raw_wholesaler_store_receipts"

def parse_supplier_file(file_path):
    filename = os.path.basename(file_path)
    items = []
    if filename.endswith(".json"):
        with open(file_path, "r") as f:
            data = json.load(f)
            for item in data.get("items", []):
                items.append((item["prod_id"], int(item["delivered_qty"])))
    elif filename.endswith(".csv"):
        with open(file_path, "r") as f:
            lines = f.readlines()
            for line in lines[1:]:
                parts = line.strip().split(";")
                if len(parts) == 2:
                    items.append((parts[0].strip(), int(parts[1].strip())))
    elif "key-value" in filename:
        with open(file_path, "r") as f:
            for line in f:
                if "PRODUCT:" in line:
                    match_prod = re.search(r"PRODUCT:\s*(P_\d+)", line)
                    match_qty = re.search(r"DELIVERED_QTY:\s*(\d+)", line)
                    if match_prod and match_qty:
                        items.append((match_prod.group(1), int(match_qty.group(1))))
    elif "text-template" in filename:
        with open(file_path, "r") as f:
            for line in f:
                match = re.search(r"delivered\s+(\d+)\s+units\s+of\s+product\s+(P_\d+)", line)
                if match:
                    items.append((match.group(2), int(match.group(1))))
    return items

def parse_order_file(file_path):
    filename = os.path.basename(file_path)
    items = []
    if filename.endswith(".json"):
        with open(file_path, "r") as f:
            data = json.load(f)
            for item in data.get("items", []):
                items.append((item["prod_id"], int(item["qty"])))
    elif filename.endswith(".csv"):
        with open(file_path, "r") as f:
            lines = f.readlines()
            for line in lines[1:]:
                parts = line.strip().split(";")
                if len(parts) == 2:
                    items.append((parts[0].strip(), int(parts[1].strip())))
    elif "key-value" in filename:
        with open(file_path, "r") as f:
            for line in f:
                if "ORDER_PRODUCT:" in line:
                    match_prod = re.search(r"ORDER_PRODUCT:\s*(P_\d+)", line)
                    match_qty = re.search(r"ORDER_QTY:\s*(\d+)", line)
                    if match_prod and match_qty:
                        items.append((match_prod.group(1), int(match_qty.group(1))))
    elif "text-template" in filename:
        with open(file_path, "r") as f:
            for line in f:
                match = re.search(r"deliver\s+(\d+)\s+units\s+of\s+product\s+(P_\d+)", line)
                if match:
                    items.append((match.group(2), int(match.group(1))))
    return items

def run_simulation():
    print("Loading sales log...")
    df = pd.read_csv("/app/sales_log.csv")
    print(f"Loaded {len(df)} sales transactions.")

    # Group sales by Day, Store_ID, Product_ID to process efficiently
    # Keep the exact consumer rows order by sorting by original index
    df["original_index"] = df.index

    # We will simulate day by day from 1 to 365
    # Wholesaler inventory: prod_id -> list of {"qty": qty, "producer": supplier_id, "day": day}
    wh_inventory = {}

    # Store inventory: (store_id, prod_id) -> list of {"qty": qty, "producer": supplier_id, "day": day}
    store_inventory = {}

    underflow_count = 0

    # Cache file paths to avoid globbing inside the loop
    print("Caching file paths...")
    wh_files_by_day = {}
    for fpath in glob.glob(os.path.join(RAW_WHOLESALER_DIR, "*.txt")):
        m = re.search(r"day_(\d+)_", fpath)
        if m:
            d = int(m.group(1))
            if d not in wh_files_by_day:
                wh_files_by_day[d] = []
            wh_files_by_day[d].append(fpath)

    st_files_by_day = {}
    for fpath in glob.glob(os.path.join(RAW_STORE_DIR, "*.txt")):
        m = re.search(r"day_(\d+)_", fpath)
        if m:
            d = int(m.group(1))
            if d not in st_files_by_day:
                st_files_by_day[d] = []
            st_files_by_day[d].append(fpath)

    sup_files_cache = {}
    for fpath in glob.glob(os.path.join(RAW_SUPPLIER_DIR, "*")):
        filename = os.path.basename(fpath)
        m = re.match(r"day_(\d+)_(PR_\d+)_", filename)
        if m:
            d, pr = int(m.group(1)), m.group(2)
            sup_files_cache[(d, pr)] = fpath

    ord_files_cache = {}
    for fpath in glob.glob(os.path.join(RAW_ORDERS_DIR, "*")):
        filename = os.path.basename(fpath)
        m = re.match(r"day_(\d+)_(S_\d+)_", filename)
        if m:
            d, s = int(m.group(1)), m.group(2)
            ord_files_cache[(d, s)] = fpath

    print("Starting simulation loop...")
    for d in range(1, 366):
        if d % 50 == 0 or d == 1:
            print(f"Simulating Day {d}...")

        # --- STEP 1: Wholesaler receives supplier deliveries ---
        wh_receipt_files = wh_files_by_day.get(d, [])
        wh_receipts = []
        for fpath in wh_receipt_files:
            with open(fpath, "r") as f:
                content = f.read()
                supplier_id = re.search(r"SUPPLIER_ID:\s*(PR_\d+)", content).group(1)
                seq = int(re.search(r"DAILY_SEQUENCE_NO:\s*(\d+)", content).group(1))
                wh_receipts.append((seq, supplier_id))
        wh_receipts.sort()

        for seq, supplier_id in wh_receipts:
            sup_fpath = sup_files_cache.get((d, supplier_id))
            if sup_fpath:
                items = parse_supplier_file(sup_fpath)
                for prod_id, qty in items:
                    if prod_id not in wh_inventory:
                        wh_inventory[prod_id] = []
                    wh_inventory[prod_id].append({"qty": qty, "producer": supplier_id, "day": d})

        # --- STEP 2: Store sales are processed using inventory from end of Day D-1 ---
        # Get sales for Day D
        day_sales = df[df["Day"] == d]
        # Sort sales by original index to preserve consumer arrival sequence
        day_sales_sorted = day_sales.sort_values("original_index")

        # Group by Store and Product
        # We will process each store and product sales
        # Note: within a day, does the sequence of consumer purchases across different stores matter?
        # No, because stores have independent inventories.
        # But within the same store and product, we must process them in sequence of original_index.
        sales_groups = day_sales_sorted.groupby(["Store_ID", "Product_ID"])
        for (store_id, prod_id), group in sales_groups:
            inv = store_inventory.get((store_id, prod_id), [])
            for idx, row in group.iterrows():
                sold_qty = int(row["Sold_Quantity"])
                if sold_qty > 0:
                    # Deduct from store inventory
                    rem = sold_qty
                    taken = []
                    while rem > 0 and inv:
                        first = inv[0]
                        if first["qty"] <= rem:
                            rem -= first["qty"]
                            taken.append((first["producer"], first["qty"]))
                            inv.pop(0)
                        else:
                            first["qty"] -= rem
                            taken.append((first["producer"], rem))
                            rem = 0
                    if rem > 0:
                        underflow_count += 1
                        print(f"WARNING: Underflow for Store {store_id}, Product {prod_id} on Day {d}: needed {sold_qty}, short by {rem}")
            store_inventory[(store_id, prod_id)] = inv

        # --- STEP 3: Wholesaler fulfills store orders, delivered to stores at end of Day D ---
        st_receipt_files = st_files_by_day.get(d, [])
        st_receipts = []
        for fpath in st_receipt_files:
            with open(fpath, "r") as f:
                content = f.read()
                store_id = re.search(r"STORE_ID:\s*(S_\d+)", content).group(1)
                seq = int(re.search(r"DAILY_SEQUENCE_NO:\s*(\d+)", content).group(1))
                total_qty = int(re.search(r"TOTAL_DELIVERED_UNITS:\s*(\d+)", content).group(1))
                st_receipts.append((seq, store_id, total_qty))
        st_receipts.sort()

        for seq, store_id, expected_total_qty in st_receipts:
            ord_fpath = ord_files_cache.get((d, store_id))
            if ord_fpath:
                ordered_items = parse_order_file(ord_fpath)
                for prod_id, qty in ordered_items:
                    available_batches = wh_inventory.get(prod_id, [])
                    total_avail = sum(b["qty"] for b in available_batches)
                    to_fulfill = min(qty, total_avail)

                    # Deduct from wholesaler and add to store intake
                    rem = to_fulfill
                    intake_batches = []
                    while rem > 0 and available_batches:
                        first = available_batches[0]
                        if first["qty"] <= rem:
                            rem -= first["qty"]
                            intake_batches.append({"qty": first["qty"], "producer": first["producer"], "day": first["day"]})
                            available_batches.pop(0)
                        else:
                            first["qty"] -= rem
                            intake_batches.append({"qty": rem, "producer": first["producer"], "day": first["day"]})
                            rem = 0

                    # Append intake to store inventory (available starting Day D+1)
                    if (store_id, prod_id) not in store_inventory:
                        store_inventory[(store_id, prod_id)] = []
                    store_inventory[(store_id, prod_id)].extend(intake_batches)

    print(f"\nSimulation complete. Total underflow events: {underflow_count}")

if __name__ == "__main__":
    run_simulation()

