                                has_dropped = False
                                if not is_omitted:
                                    r_idx = [r for r, master_c in mapping.items() if master_c == c][0]
                                    observed_demand = obs_demands[r_idx]
                                    if observed_demand <= 1 and B[s][c] >= 2:
                                        has_dropped = True

                                if is_omitted or has_dropped:
                                    total_rejections += 1
                                    # If they bought from exactly ONE producer on d-1, that producer is BAD!
                                    if len(prev_producers) == 1:
                                        sole_bad_producers.add(prev_producers[0])
                                    recovery_days[s][c] = 14

                for c in range(N):
                    if recovery_days[s][c] > 0:
                        recovery_days[s][c] -= 1

                inv = store_inventory[s]
                for r in range(len(obs_demands)):
                    c = mapping.get(r)
                    if c is not None:
                        sold_qty = obs_solds[r]
                        if sold_qty > 0:
                            rem = sold_qty
                            taken_producers = []
                            while rem > 0 and inv:
                                first = inv[0]
                                if first["qty"] <= rem:
                                    rem -= first["qty"]
                                    taken_producers.append(first["producer"])
                                    inv.pop(0)
                                else:
                                    first["qty"] -= rem
                                    taken_producers.append(first["producer"])
                                    rem = 0
                            purchased_producers[s][d][c] = list(set(taken_producers))
                store_inventory[s] = inv

