import os
import glob
import re
import json
import pandas as pd
import numpy as np

RAW_ORDERS_DIR = "/app/raw_orders"
RAW_SUPPLIER_DIR = "/app/raw_supplier_receipts"
RAW_WHOLESALER_DIR = "/app/raw_wholesaler_receipts"
RAW_STORE_DIR = "/app/raw_wholesaler_store_receipts"

def parse_supplier_file(file_path):
    filename = os.path.basename(file_path)
    items = []
    if filename.endswith(".json"):
        with open(file_path, "r") as f:
            data = json.load(f)
            for item in data.get("items", []):
                items.append((item["prod_id"], int(item["delivered_qty"])))
    elif filename.endswith(".csv"):
        with open(file_path, "r") as f:
            lines = f.readlines()
            for line in lines[1:]:
                parts = line.strip().split(";")
                if len(parts) == 2:
                    items.append((parts[0].strip(), int(parts[1].strip())))
    elif "key-value" in filename:
        with open(file_path, "r") as f:
            for line in f:
                if "PRODUCT:" in line:
                    match_prod = re.search(r"PRODUCT:\s*(P_\d+)", line)
                    match_qty = re.search(r"DELIVERED_QTY:\s*(\d+)", line)
                    if match_prod and match_qty:
                        items.append((match_prod.group(1), int(match_qty.group(1))))
    elif "text-template" in filename:
        with open(file_path, "r") as f:
            for line in f:
                match = re.search(r"delivered\s+(\d+)\s+units\s+of\s+product\s+(P_\d+)", line)
                if match:
                    items.append((match.group(2), int(match.group(1))))
    return items

def parse_order_file(file_path):
    filename = os.path.basename(file_path)
    items = []
    if filename.endswith(".json"):
        with open(file_path, "r") as f:
            data = json.load(f)
            for item in data.get("items", []):
                items.append((item["prod_id"], int(item["qty"])))
    elif filename.endswith(".csv"):
        with open(file_path, "r") as f:
            lines = f.readlines()
            for line in lines[1:]:
                parts = line.strip().split(";")
                if len(parts) == 2:
                    items.append((parts[0].strip(), int(parts[1].strip())))
    elif "key-value" in filename:
        with open(file_path, "r") as f:
            for line in f:
                if "ORDER_PRODUCT:" in line:
                    match_prod = re.search(r"ORDER_PRODUCT:\s*(P_\d+)", line)
                    match_qty = re.search(r"ORDER_QTY:\s*(\d+)", line)
                    if match_prod and match_qty:
                        items.append((match_prod.group(1), int(match_qty.group(1))))
    elif "text-template" in filename:
        with open(file_path, "r") as f:
            for line in f:
                match = re.search(r"deliver\s+(\d+)\s+units\s+of\s+product\s+(P_\d+)", line)
                if match:
                    items.append((match.group(2), int(match.group(1))))
    return items

def align_day(obs, expected_demands, B):
    M = len(obs)
    N = len(expected_demands)
    dp = np.zeros((M + 1, N + 1))
    for i in range(M + 1):
        dp[i, 0] = i * 100.0
    for j in range(N + 1):
        dp[0, j] = sum(expected_demands[:j])
    for i in range(1, M + 1):
        for j in range(1, N + 1):
            cost_match = dp[i-1, j-1] + abs(obs[i-1] - expected_demands[j-1])
            cost_omit = dp[i, j-1] + expected_demands[j-1]
            dp[i, j] = min(cost_match, cost_omit)
    i, j = M, N
    mapping = {}
    while i > 0 or j > 0:
        if i > 0 and j > 0:
            cost_match = dp[i-1, j-1] + abs(obs[i-1] - expected_demands[j-1])
            if dp[i, j] == cost_match:
                mapping[i-1] = j-1
                i -= 1
                j -= 1
                continue
        if j > 0:
            j -= 1
        else:
            i -= 1
    return mapping

def main():
    print("Loading sales log...")
    df = pd.read_csv("/app/sales_log.csv")
    df["original_index"] = df.index

    # Cache file paths
    print("Caching file paths...")
    wh_files_by_day = {}
    for fpath in glob.glob(os.path.join(RAW_WHOLESALER_DIR, "*.txt")):
        m = re.search(r"day_(\d+)_", fpath)
        if m:
            d = int(m.group(1))
            if d not in wh_files_by_day:
                wh_files_by_day[d] = []
            wh_files_by_day[d].append(fpath)

    st_files_by_day = {}
    for fpath in glob.glob(os.path.join(RAW_STORE_DIR, "*.txt")):
        m = re.search(r"day_(\d+)_", fpath)
        if m:
            d = int(m.group(1))
            if d not in st_files_by_day:
                st_files_by_day[d] = []
            st_files_by_day[d].append(fpath)

    sup_files_cache = {}
    for fpath in glob.glob(os.path.join(RAW_SUPPLIER_DIR, "*")):
        filename = os.path.basename(fpath)
        m = re.match(r"day_(\d+)_(PR_\d+)_", filename)
        if m:
            d, pr = int(m.group(1)), m.group(2)
            sup_files_cache[(d, pr)] = fpath

    ord_files_cache = {}
    for fpath in glob.glob(os.path.join(RAW_ORDERS_DIR, "*")):
        filename = os.path.basename(fpath)
        m = re.match(r"day_(\d+)_(S_\d+)_", filename)
        if m:
            d, s = int(m.group(1)), m.group(2)
            ord_files_cache[(d, s)] = fpath

    all_products = sorted([f"P_{i}" for i in range(1, 31)], key=lambda x: int(x.split("_")[1]))
    stores = [f"S_{i}" for i in range(1, 11)]

    # Structures for ALL products:
    # Wholesaler inventory: product -> list of batches
    wh_inventory = {p: [] for p in all_products}
    # Store inventory: (store, product) -> list of batches
    store_inventory = {(s, p): [] for s in stores for p in all_products}

    # Consumer and state structures:
    # num_consumers: (store, product) -> N
    num_consumers = {}
    # B: (store, product) -> base demands (array of size N)
    B = {}
    # recovery_days: (store, product) -> remaining days of recovery (array of size N)
    recovery_days = {}
    # purchased_producers: (store, product) -> day -> c -> list of producers
    purchased_producers = {}

    print("Initializing consumer profiles and tracking state...")
    for p in all_products:
        prod_sales = df[df["Product_ID"] == p]
        for s in stores:
            s_sales = prod_sales[prod_sales["Store_ID"] == s]
            N = s_sales.groupby("Day").size().max()
            num_consumers[(s, p)] = N

            day1_demands = list(s_sales[s_sales["Day"] == 1].sort_values("original_index")["Reported_Demand"])
            if len(day1_demands) < N:
                day1_demands += [2] * (N - len(day1_demands))
            B[(s, p)] = np.array(day1_demands[:N], dtype=float)
            recovery_days[(s, p)] = np.zeros(N, dtype=int)
            purchased_producers[(s, p)] = {d: {} for d in range(1, 366)}

    # Results: product -> set of sole bad producers
    sole_bad_producers = {p: set() for p in all_products}
    total_rejections = {p: 0 for p in all_products}

    # We will simulate day by day
    for d in range(1, 366):
        if d % 50 == 0 or d == 1:
            print(f"Simulating Day {d}...")

        # --- STEP 1: Wholesaler receives supplier deliveries ---
        wh_receipt_files = wh_files_by_day.get(d, [])
        wh_receipts = []
        for fpath in wh_receipt_files:
            with open(fpath, "r") as f:
                content = f.read()
                supplier_id = re.search(r"SUPPLIER_ID:\s*(PR_\d+)", content).group(1)
                seq = int(re.search(r"DAILY_SEQUENCE_NO:\s*(\d+)", content).group(1))
                wh_receipts.append((seq, supplier_id))
        wh_receipts.sort()

        for seq, supplier_id in wh_receipts:
            sup_fpath = sup_files_cache.get((d, supplier_id))
            if sup_fpath:
                items = parse_supplier_file(sup_fpath)
                for pid, qty in items:
                    if pid in wh_inventory:
                        wh_inventory[pid].append({"qty": qty, "producer": supplier_id, "day": d})

        # --- STEP 2: Store sales are processed using inventory from end of Day D-1 ---
        # Get sales for Day D
        day_sales = df[df["Day"] == d]
        day_sales_sorted = day_sales.sort_values("original_index")

        # To avoid slow pandas filtering, group by Store and Product in memory
        sales_groups = day_sales_sorted.groupby(["Store_ID", "Product_ID"])
        for (store_id, prod_id), group in sales_groups:
            N = num_consumers[(store_id, prod_id)]
            obs_demands = list(group["Reported_Demand"])
            obs_solds = list(group["Sold_Quantity"])

            # Compute recovery factors and expected demands
            expected_demands = []
            rec_days = recovery_days[(store_id, prod_id)]
            base_dem = B[(store_id, prod_id)]
            for c in range(N):
                r_days = rec_days[c]
                factor = 1.0
                if r_days > 0:
                    if r_days >= 12:
                        factor = 0.2
                    elif r_days >= 8:
                        factor = 0.5
                    else:
                        factor = 0.8
                expected_demands.append(base_dem[c] * factor)
            expected_demands = np.array(expected_demands)

            # Align observed rows with master consumers
            mapping = align_day(obs_demands, expected_demands, base_dem)

            # Analyze rejections
            if d >= 2:
                for c in range(N):
                    if rec_days[c] == 0:
                        prev_producers = purchased_producers[(store_id, prod_id)][d-1].get(c, [])
                        if prev_producers:
                            is_omitted = (c not in mapping.values())
                            has_dropped = False
                            if not is_omitted:
                                r_idx = [r for r, master_c in mapping.items() if master_c == c][0]
                                observed_demand = obs_demands[r_idx]
                                if observed_demand <= 1 and base_dem[c] >= 2:
                                    has_dropped = True

                            if is_omitted or has_dropped:
                                total_rejections[prod_id] += 1
                                if len(prev_producers) == 1:
                                    sole_bad_producers[prod_id].add(prev_producers[0])
                                rec_days[c] = 14  # enters recovery on day d

            # Decrement recovery days left
            for c in range(N):
                if rec_days[c] > 0:
                    rec_days[c] -= 1
            recovery_days[(store_id, prod_id)] = rec_days

            # Process sales to deduct from store inventory and record purchases
            inv = store_inventory[(store_id, prod_id)]
            for r in range(len(obs_demands)):
                c = mapping.get(r)
                if c is not None:
                    sold_qty = obs_solds[r]
                    if sold_qty > 0:
                        rem = sold_qty
                        taken_producers = []
                        while rem > 0 and inv:
                            first = inv[0]
                            if first["qty"] <= rem:
                                rem -= first["qty"]
                                taken_producers.append(first["producer"])
                                inv.pop(0)
                            else:
                                first["qty"] -= rem
                                taken_producers.append(first["producer"])
                                rem = 0
                        purchased_producers[(store_id, prod_id)][d][c] = list(set(taken_producers))
            store_inventory[(store_id, prod_id)] = inv

        # --- STEP 3: Wholesaler fulfills store orders at the end of Day D ---
        st_receipt_files = st_files_by_day.get(d, [])
        st_receipts = []
        for fpath in st_receipt_files:
            with open(fpath, "r") as f:
                content = f.read()
                store_id = re.search(r"STORE_ID:\s*(S_\d+)", content).group(1)
                seq = int(re.search(r"DAILY_SEQUENCE_NO:\s*(\d+)", content).group(1))
                total_qty = int(re.search(r"TOTAL_DELIVERED_UNITS:\s*(\d+)", content).group(1))
                st_receipts.append((seq, store_id, total_qty))
        st_receipts.sort()

        for seq, store_id, expected_total_qty in st_receipts:
            ord_fpath = ord_files_cache.get((d, store_id))
            if ord_fpath:
                ordered_items = parse_order_file(ord_fpath)
                for pid, qty in ordered_items:
                    if pid in wh_inventory:
                        wh_inv_pid = wh_inventory[pid]
                        total_avail = sum(b["qty"] for b in wh_inv_pid)
                        to_fulfill = min(qty, total_avail)

                        rem = to_fulfill
                        intake_batches = []
                        while rem > 0 and wh_inv_pid:
                            first = wh_inv_pid[0]
                            if first["qty"] <= rem:
                                rem -= first["qty"]
                                intake_batches.append({"qty": first["qty"], "producer": first["producer"], "day": first["day"]})
                                wh_inv_pid.pop(0)
                            else:
                                first["qty"] -= rem
                                intake_batches.append({"qty": rem, "producer": first["producer"], "day": first["day"]})
                                rem = 0

                        store_inventory[(store_id, pid)].extend(intake_batches)

    # Format output
    confirmed_bad_by_prod = {}
    print("\nSimulation and tracking complete. Results:")
    for p in all_products:
        p_bad = sorted(list(sole_bad_producers[p]), key=lambda x: int(x.split('_')[1]))
        print(f"  {p}: {len(total_rejections)} rejections, confirmed bad: {p_bad}")
        confirmed_bad_by_prod[p] = p_bad

    print("\nSaving final answer to /app/answer.json...")
    with open("/app/answer.json", "w") as f:
        json.dump(confirmed_bad_by_prod, f)
    print("Done!")

if __name__ == "__main__":
