                        factor = 0.2
                    elif r_days >= 8:
                        factor = 0.5
                    else:
                        factor = 0.8
                expected_demands.append(base_dem[c] * factor)
            expected_demands = np.array(expected_demands)

            # Align observed rows with master consumers
            mapping = align_day(obs_demands, expected_demands, base_dem)

            # Analyze rejections
            if d >= 2:
                for c in range(N):
                    if rec_days[c] == 0:
                        prev_producers = purchased_producers[(store_id, prod_id)][d-1].get(c, [])
                        if prev_producers:
                            is_omitted = (c not in mapping.values())
                            has_dropped = False
                            if not is_omitted:
                                r_idx = [r for r, master_c in mapping.items() if master_c == c][0]
                                observed_demand = obs_demands[r_idx]
                                if observed_demand <= 1 and base_dem[c] >= 2:
                                    has_dropped = True

                            if is_omitted or has_dropped:
                                total_rejections[prod_id] += 1
                                if len(prev_producers) == 1:
                                    sole_bad_producers[prod_id].add(prev_producers[0])
                                rec_days[c] = 14  # enters recovery on day d

            # Decrement recovery days left
            for c in range(N):
                if rec_days[c] > 0:
                    rec_days[c] -= 1
