                        while rem > 0 and wh_inv_pid:
                            first = wh_inv_pid[0]
                            if first["qty"] <= rem:
                                rem -= first["qty"]
                                intake_batches.append({"qty": first["qty"], "producer": first["producer"], "day": first["day"]})
                                wh_inv_pid.pop(0)
                            else:
                                first["qty"] -= rem
                                intake_batches.append({"qty": rem, "producer": first["producer"], "day": first["day"]})
                                rem = 0

                        store_inventory[(store_id, pid)].extend(intake_batches)

    # Format output
    confirmed_bad_by_prod = {}
    print("\nSimulation and tracking complete. Results:")
    for p in all_products:
        p_bad = sorted(list(sole_bad_producers[p]), key=lambda x: int(x.split('_')[1]))
        print(f"  {p}: {len(total_rejections)} rejections, confirmed bad: {p_bad}")
        confirmed_bad_by_prod[p] = p_bad

    print("\nSaving final answer to /app/answer.json...")
